frappe.ui.form.on("Vehicle Purchase Order", {
    job_quote(frm) {
        if (!frm.doc.job_quote) return;

        frappe.call({
            method: "vehicle.vehicle.doctype.vehicle_purchase_order.vehicle_purchase_order.get_job_quote",
            args: {
                source_name: frm.doc.job_quote
            },
            callback: function(r) {
                if (r.message) {
                    // clear all tables first
                    for (let i = 1; i <= 10; i++) {
                        frm.clear_table(`table_${i}`);
                    }

                    // set all values from server
                    frm.set_value(r.message);

                    frm.refresh();
                }
            }
        });
    }
});

frappe.ui.form.on("GRV", {
    grv(frm) {
        if (!frm.doc.purchase_order) return;

        frappe.call({
            method: "vehicle.vehicle.doctype.grv.grv.get_vehicle_order",
            args: {
                source_name: frm.doc.purchase_order
            },
            callback: ({ message }) => {
                if (!message) return;

                // 🔹 1. Set simple fields (EXCLUDE purchase_order)
                let simple_fields = {};

                Object.keys(message).forEach(key => {
                    if (!key.startsWith("table_") && key !== "purchase_order") {
                        simple_fields[key] = message[key];
                    }
                });

                frm.set_value(simple_fields);

                // 🔹 2. Populate child tables
                for (let i = 1; i <= 10; i++) {
                    let table_name = `table_${i}`;
                    frm.clear_table(table_name);

                    (message[table_name] || []).forEach(row => {
                        let child = frm.add_child(table_name);

                        child.item_code = row.item_code ? String(row.item_code) : "";
                        child.item_name = row.item_name || "";
                        child.description = row.description || "";
                        child.qty = row.qty || 0;
                        child.rate = row.rate || 0;
                        child.balance_qty = row.balance_qty || 0;
                        child.amount = row.amount || 0;
                        child.supplier = row.supplier || 0;
                    });

                    frm.refresh_field(table_name);
                }

                frm.refresh();
            }
        });
    },

    purchase_order(frm) {
        if (frm.doc.purchase_order) {
            frm.trigger("grv");
        }
    }
});

frappe.ui.form.on("Maintainance Type GRV", {
    add_qty: function(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        if (!row) return;

        // 🔹 Check balance BEFORE creating dialog
        if (!row.balance_qty || row.balance_qty <= 0) {
            frappe.msgprint({
                title: __('No balance left'),
                message: __('This item has no remaining balance.'),
                indicator: 'red'
            });
            return;
        }

        const d = new frappe.ui.Dialog({
            title: __("Edit Item"),
            fields: [
                {
                    label: "Item Code",
                    fieldname: "item_code",
                    fieldtype: "Data",
                    default: row.item_code,
                    read_only: 1
                },
                {
                    label: "Balance Left",
                    fieldname: "balance_qty",
                    fieldtype: "Float",
                    default: row.balance_qty,
                    read_only: 1
                },
                {
                    label: "Qty to Add",
                    fieldname: "qty",
                    fieldtype: "Float",
                    default: row.qty || 1,
                    description: __("Cannot exceed balance left")
                }
            ],
            primary_action_label: "Save and Submit",
            primary_action(values) {
                if (values.qty > row.balance_qty) {
                    frappe.msgprint({
                        title: __('Invalid Quantity'),
                        message: __('Qty cannot exceed balance left! ⚠️'),
                        indicator: 'red'
                    });
                    return;
                }

                frappe.call({
                    method: "vehicle.vehicle.doctype.grv.grv.process_grv_item",
                    args: {
                        item_code: row.item_code,
                        qty: values.qty,
                        purchase_order: frm.doc.purchase_order
                    },
                    callback: function(r) {
                        if (r.message && r.message.success) {
                            // Update child row locally
                            const new_balance = row.balance_qty - values.qty;
                            const new_received = (row.received_qty || 0) + values.qty;

                            frappe.model.set_value(cdt, cdn, "balance_qty", new_balance);
                            frappe.model.set_value(cdt, cdn, "received_qty", new_received);
                            frappe.model.set_value(cdt, cdn, "submitted", 1);

                            frappe.msgprint({
                                title: __('Success'),
                                message: __('Row updated, received qty increased and balance decreased 🔥'),
                                indicator: 'green'
                            });

                            // 🔹 Blur focused element then hide dialog
                            $(document.activeElement).blur();
                            d.hide();

                            // 🔹 Auto-save the whole GRV document
                            frm.save_or_update();
                        } else {
                            frappe.msgprint({
                                title: __('Error'),
                                message: __('Error processing item: ') + (r.message?.msg || ''),
                                indicator: 'red'
                            });
                            $(document.activeElement).blur();
                            d.hide();
                        }
                    }
                });
            }
        });

        d.show();
    }
});

frappe.ui.form.on('Maintainance Type', {
    qty: function(frm, cdt, cdn) {
        calculate_totals(frm);
    },
    rate: function(frm, cdt, cdn) {
        calculate_totals(frm);
    }
});

function calculate_totals(frm) {
    let grand_qty = 0;
    let grand_amount = 0;

    for (let i = 1; i <= 10; i++) {
        let table_name = `table_${i}`;
        let total_qty_field = `task${i}_total_qty`;
        let total_amount_field = `task${i}_total_amount`;

        let table_rows = frm.doc[table_name] || [];

        let table_qty = 0;
        let table_amount = 0;

        table_rows.forEach(r => {
            r.amount = (r.qty || 0) * (r.rate || 0); // update row amount
            table_qty += r.qty || 0;
            table_amount += r.amount || 0;
        });

        // refresh row amounts in UI
        frm.refresh_field(table_name);

        // set per-table totals
        frappe.model.set_value(frm.doctype, frm.docname, total_qty_field, table_qty);
        frappe.model.set_value(frm.doctype, frm.docname, total_amount_field, table_amount);
        frm.refresh_field(total_qty_field);
        frm.refresh_field(total_amount_field);

        // add to grand totals
        grand_qty += table_qty;
        grand_amount += table_amount;
    }

    // 🔹 set grand totals on parent
    frappe.model.set_value(frm.doctype, frm.docname, "total_quantity", grand_qty);
    frappe.model.set_value(frm.doctype, frm.docname, "total_amount", grand_amount);

    frm.refresh_field("total_quantity");
    frm.refresh_field("total_amount");
}

