// Child table logic (Maintainance Type GRV)
frappe.ui.form.on('Maintainance Type GRV', {

	qty(frm, cdt, cdn) {
		calculate_balance(frm, cdt, cdn);
	},

	received_qty(frm, cdt, cdn) {
		calculate_balance(frm, cdt, cdn);
	},

	add_qty(frm, cdt, cdn) {
		let row = locals[cdt][cdn];

		// 🚫 no balance
		if ((row.balance_qty || 0) <= 0) {
			frappe.msgprint("This item has no remaining balance.");
			frappe.model.set_value(cdt, cdn, "add_qty", 0);
			return;
		}

		// 🚫 over-add
		if ((row.add_qty || 0) > (row.balance_qty || 0)) {
			frappe.msgprint("Cannot add more than remaining balance.");
			frappe.model.set_value(cdt, cdn, "add_qty", 0);
			return;
		}

		// 🔥 update received qty (like Sales Invoice behavior)
		let new_received = (row.received_qty || 0) + (row.add_qty || 0);

		frappe.model.set_value(cdt, cdn, "received_qty", new_received);

		// reset add_qty
		frappe.model.set_value(cdt, cdn, "add_qty", 0);
	}
});


// 🔧 Shared function
function calculate_balance(frm, cdt, cdn) {
	let row = locals[cdt][cdn];

	let ordered = row.qty || 0;
	let received = row.received_qty || 0;

	let balance = ordered - received;

	if (balance < 0) balance = 0;

	row.balance_qty = balance;

	// 🔥 refresh ALL tables (like your pattern)
	for (let i = 1; i <= 10; i++) {
		frm.refresh_field(`table_${i}`);
	}
}

